import play.api.mvc._
import play.api.libs.json._

// Assuming Order model and OrderRepository trait are defined elsewhere

class OrderController @Inject()(val orderRepository: OrderRepository) extends Controller {

  def getOrder(orderId: Long): Action[AnyContent] = Action {
    val order = orderRepository.findById(orderId)
